<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();$rows=[];$ready=false;if(vp3_db_available()){try{$stmt=vp3_db()->prepare("SELECT pa.*,p.title project_title FROM project_assets pa JOIN creative_projects p ON p.id=pa.project_id WHERE p.customer_id=? AND pa.visibility IN ('customer','shared') AND pa.status='active' ORDER BY pa.updated_at DESC");$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();$ready=true;}catch(Throwable){}}$pageTitle='Asset Library';require VP3_ROOT.'/includes/account-header.php';?>
<div class="page-head"><div><span class="eyebrow">Shared creative files</span><h1>Asset library</h1><p class="helper">Brand, artwork, scripts, audio, video, contracts, and launch references organized by project.</p></div></div><?php if(!$ready):?><div class="notice">Import the creative operations migration to enable the asset library.</div><?php else:?><div class="asset-grid"><?php foreach($rows as $asset):?><article class="asset-card"><span><?=vp3_e($asset['project_title'].' · '.$asset['category'])?></span><h3><?=vp3_e($asset['title'])?></h3><p><?=vp3_e($asset['description'])?></p><small>Version <?=(int)$asset['version_number']?> · <?=vp3_e(str_replace('_',' ',$asset['approval_status']))?></small><?php if($url=vp3_public_https_url($asset['external_url'])):?><a class="button small secondary" href="<?=vp3_e($url)?>" target="_blank" rel="noopener noreferrer">Open asset</a><?php endif;?></article><?php endforeach;?><?php if(!$rows):?><div class="empty-state"><p>No shared assets yet.</p></div><?php endif;?></div><?php endif;?>
<?php require VP3_ROOT.'/includes/account-footer.php'; ?>
